def age_distribution(items: list[RetroActionItem]) -> dict:
    open_items = [i for i in items if i.status in ("open", "in_progress")]
    if not open_items:
        return {"normal": 0, "warning": 0, "stale": 0}

    normal  = [i for i in open_items if i.days_open() <= 14]
    warning = [i for i in open_items if 14 < i.days_open() <= 30]
    stale   = [i for i in open_items if i.days_open() > 30]

    return {
        "normal":  len(normal),
        "warning": len(warning),
        "stale":   len(stale),
        "stale_items": [
            {"description": i.description, "owner": i.owner, "days_open": i.days_open()}
            for i in stale
        ],
    }
